3_real_world_example.code:
console.log('1. Start');

setTimeout(() => {
  console.log('3. Event Loop let me in!');
}, 0);

console.log('2. Doing heavy sync work...');
// Simulating a 2-second blocking operation
const start = Date.now();
while (Date.now() - start < 2000) {}

console.log('Finished sync work');

// Output:
// 1. Start
// 2. Doing heavy sync work...
// Finished sync work
// 3. Event Loop let me in! 

// Even though setTimeout was 0ms, it waited 2+ seconds 
// because the Event Loop could not push it until the while-loop finished.

